// Filter only public groups and sort by member count (largest first)
const publicGroups = facebookGroups
  .filter(group => group.type === "Public")
  .sort((a, b) => b.members - a.members);

// Get trigger data
const triggerData = $input.first().json;
const maxGroups = triggerData.maxGroups || 10; // Default to top 10 groups
const apifyToken = triggerData.apifyToken || 'apify_api_QfRR0XzZtbGi14p8xaTMc2Fg44a9aW0W5CQM';

// Take top groups based on maxGroups parameter
const selectedGroups = publicGroups.slice(0, maxGroups);

// Log the selection
console.log(`Selected ${selectedGroups.length} public Facebook groups for scraping`);
selectedGroups.forEach(group => {
  console.log(`- ${group.name}: ${group.members.toLocaleString()} members`);
});

// Return the selected groups with Apify configuration
return selectedGroups.map(group => ({
  json: {
    groupName: group.name,
    groupUrl: group.url,
    memberCount: group.members,
    apifyToken: apifyToken,
    scrapeType: 'members',
    maxMembers: Math.min(group.members, 1000), // Limit to 1000 members per group
    customAudienceName: `Portal Flanary - ${group.name}`,
    timestamp: new Date().toISOString()
  }
}));

// Process Apify scraping results
const input = $input.first().json;
const groupData = $('Initialize Facebook Groups').first().json;

// Check if scraping was successful
if (!input.data || !input.data.id) {
  throw new Error(`Apify scraping failed: ${JSON.stringify(input)}`);
}

const runId = input.data.id;
console.log(`Apify run started with ID: ${runId}`);

// Return the run ID and group data for monitoring
return [{
  json: {
    apifyRunId: runId,
    groupName: groupData.groupName,
    groupUrl: groupData.groupUrl,
    memberCount: groupData.memberCount,
    customAudienceName: groupData.customAudienceName,
    status: 'scraping_started',
    timestamp: new Date().toISOString()
  }
}];

// Process scraped Facebook member data
const scrapedData = $input.all();
const groupData = $('Initialize Facebook Groups').first().json;

// Check if we have data
if (!scrapedData || scrapedData.length === 0) {
  console.log('No scraped data available yet, will retry later');
  return [{
    json: {
      groupName: groupData.groupName,
      status: 'no_data_yet',
      message: 'Scraping still in progress',
      timestamp: new Date().toISOString()
    }
  }];
}

// Extract member data from all scraped items
const allMembers = [];
scrapedData.forEach(item => {
  if (item.json && Array.isArray(item.json)) {
    item.json.forEach(member => {
      if (member && member.profileUrl) {
        allMembers.push({
          profileUrl: member.profileUrl,
          name: member.name || '',
          location: member.location || '',
          joinedDate: member.joinedDate || '',
          postsCount: member.postsCount || 0,
          groupName: groupData.groupName,
          scrapedAt: new Date().toISOString()
        });
      }
    });
  }
});

console.log(`Scraped ${allMembers.length} members from ${groupData.groupName}`);

// Filter and clean the data
const validMembers = allMembers.filter(member => {
  return member.profileUrl && 
         member.profileUrl.includes('facebook.com') &&
         member.profileUrl !== 'https://www.facebook.com/';
});

// Remove duplicates based on profile URL
const uniqueMembers = validMembers.filter((member, index, self) =>
  index === self.findIndex(m => m.profileUrl === member.profileUrl)
);

console.log(`Valid unique members: ${uniqueMembers.length}`);

// Prepare data for Facebook Custom Audience
const customAudienceData = {
  groupName: groupData.groupName,
  customAudienceName: groupData.customAudienceName,
  memberCount: uniqueMembers.length,
  members: uniqueMembers.map(member => ({
    profileUrl: member.profileUrl,
    name: member.name,
    location: member.location
  })),
  status: 'data_ready',
  timestamp: new Date().toISOString()
};

return [{
  json: customAudienceData
}];

// Create Facebook Custom Audience (Mock Implementation)
const memberData = $input.first().json;

// In a real implementation, this would use Facebook Marketing API
// For now, we'll create a mock response
const customAudienceId = `ca_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

console.log(`Creating custom audience: ${memberData.customAudienceName}`);
console.log(`Members to add: ${memberData.memberCount}`);

// Mock Facebook API response
const facebookResponse = {
  customAudienceId: customAudienceId,
  customAudienceName: memberData.customAudienceName,
  groupName: memberData.groupName,
  memberCount: memberData.memberCount,
  status: 'created',
  message: 'Custom audience created successfully',
  timestamp: new Date().toISOString()
};

// In production, this would be the actual Facebook API call:
/*
const facebookApiResponse = await fetch('https://graph.facebook.com/v18.0/act_<AD_ACCOUNT_ID>/customaudiences', {
